CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;
CREATE TABLE "Categories" (
    "CategoryId" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" text NOT NULL,
    "Icon" text,
    "ColorHex" text,
    CONSTRAINT "PK_Categories" PRIMARY KEY ("CategoryId")
);

CREATE TABLE "Users" (
    "UserId" integer GENERATED BY DEFAULT AS IDENTITY,
    "FullName" text NOT NULL,
    "Email" text NOT NULL,
    "Phone" text,
    "PasswordHash" text NOT NULL,
    "Role" character varying(20) NOT NULL DEFAULT 'User',
    "AvatarUrl" text,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "LastLoginAt" timestamp with time zone,
    CONSTRAINT "PK_Users" PRIMARY KEY ("UserId")
);

CREATE TABLE "Places" (
    "PlaceId" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" text NOT NULL,
    "Description" text,
    "Address" text NOT NULL,
    "Latitude" numeric(10,7) NOT NULL,
    "Longitude" numeric(10,7) NOT NULL,
    "Phone" text,
    "Website" text,
    "OpenTime" time without time zone,
    "CloseTime" time without time zone,
    "PriceMin" numeric,
    "PriceMax" numeric,
    "AverageRating" double precision NOT NULL,
    "TotalReviews" integer NOT NULL,
    "TotalVisits" integer NOT NULL,
    "IsApproved" boolean NOT NULL,
    "IsActive" boolean NOT NULL,
    "CategoryId" integer,
    "OwnerId" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    CONSTRAINT "PK_Places" PRIMARY KEY ("PlaceId"),
    CONSTRAINT "FK_Places_Categories_CategoryId" FOREIGN KEY ("CategoryId") REFERENCES "Categories" ("CategoryId"),
    CONSTRAINT "FK_Places_Users_OwnerId" FOREIGN KEY ("OwnerId") REFERENCES "Users" ("UserId") ON DELETE RESTRICT
);

CREATE TABLE "UserTracking" (
    "TrackId" bigint GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "Latitude" numeric(10,7) NOT NULL,
    "Longitude" numeric(10,7) NOT NULL,
    "Accuracy" double precision,
    "RecordedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_UserTracking" PRIMARY KEY ("TrackId"),
    CONSTRAINT "FK_UserTracking_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("UserId") ON DELETE CASCADE
);

CREATE TABLE "PlaceImages" (
    "ImageId" integer GENERATED BY DEFAULT AS IDENTITY,
    "PlaceId" integer NOT NULL,
    "ImageUrl" text NOT NULL,
    "IsMain" boolean NOT NULL,
    "SortOrder" integer NOT NULL,
    CONSTRAINT "PK_PlaceImages" PRIMARY KEY ("ImageId"),
    CONSTRAINT "FK_PlaceImages_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId") ON DELETE CASCADE
);

CREATE TABLE "Reviews" (
    "ReviewId" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "PlaceId" integer NOT NULL,
    "Rating" tinyint NOT NULL,
    "Comment" text,
    "OwnerReply" text,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Reviews" PRIMARY KEY ("ReviewId"),
    CONSTRAINT "FK_Reviews_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId") ON DELETE RESTRICT,
    CONSTRAINT "FK_Reviews_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("UserId") ON DELETE RESTRICT
);

CREATE TABLE "VisitHistory" (
    "VisitId" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "PlaceId" integer NOT NULL,
    "CheckInTime" timestamp with time zone NOT NULL,
    "CheckOutTime" timestamp with time zone,
    "DurationMins" integer,
    "AutoDetected" boolean NOT NULL,
    "Notes" text,
    CONSTRAINT "PK_VisitHistory" PRIMARY KEY ("VisitId"),
    CONSTRAINT "FK_VisitHistory_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId") ON DELETE RESTRICT,
    CONSTRAINT "FK_VisitHistory_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("UserId") ON DELETE RESTRICT
);

