CREATE INDEX "IX_PlaceImages_PlaceId" ON "PlaceImages" ("PlaceId");

CREATE INDEX "IX_Places_CategoryId" ON "Places" ("CategoryId");

CREATE INDEX "IX_Places_Latitude_Longitude" ON "Places" ("Latitude", "Longitude");

CREATE INDEX "IX_Places_OwnerId" ON "Places" ("OwnerId");

CREATE INDEX "IX_Reviews_PlaceId" ON "Reviews" ("PlaceId");

CREATE UNIQUE INDEX "IX_Reviews_UserId_PlaceId" ON "Reviews" ("UserId", "PlaceId");

CREATE UNIQUE INDEX "IX_Users_Email" ON "Users" ("Email");

CREATE INDEX "IX_UserTracking_UserId_RecordedAt" ON "UserTracking" ("UserId", "RecordedAt");

CREATE INDEX "IX_VisitHistory_PlaceId" ON "VisitHistory" ("PlaceId");

CREATE INDEX "IX_VisitHistory_UserId" ON "VisitHistory" ("UserId");

