ALTER TABLE "Reviews" ADD "SpaceRating" smallint;

ALTER TABLE "Reviews" ADD "TasteRating" smallint;

ALTER TABLE "Places" ALTER COLUMN "Status" DROP DEFAULT;

ALTER TABLE "Places" ALTER COLUMN "Specialty" TYPE character varying(500);

