CREATE TABLE "Complaints" (
    "ComplaintId" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "PlaceId" integer,
    "ReviewId" integer,
    "Type" text NOT NULL,
    "Title" text NOT NULL,
    "Content" text NOT NULL,
    "Status" text NOT NULL,
    "AdminReply" text,
    "CreatedAt" timestamp with time zone NOT NULL,
    "ResolvedAt" timestamp with time zone,
    CONSTRAINT "PK_Complaints" PRIMARY KEY ("ComplaintId"),
    CONSTRAINT "FK_Complaints_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId"),
    CONSTRAINT "FK_Complaints_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("UserId") ON DELETE RESTRICT
);

CREATE TABLE "Messages" (
    "MessageId" integer GENERATED BY DEFAULT AS IDENTITY,
    "PlaceId" integer NOT NULL,
    "UserId" integer NOT NULL,
    "Content" text NOT NULL,
    "IsFromOwner" boolean NOT NULL,
    "ParentId" integer,
    "IsPublic" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Messages" PRIMARY KEY ("MessageId"),
    CONSTRAINT "FK_Messages_Messages_ParentId" FOREIGN KEY ("ParentId") REFERENCES "Messages" ("MessageId"),
    CONSTRAINT "FK_Messages_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId") ON DELETE CASCADE,
    CONSTRAINT "FK_Messages_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("UserId") ON DELETE CASCADE
);

CREATE TABLE "Promotions" (
    "PromoId" integer GENERATED BY DEFAULT AS IDENTITY,
    "PlaceId" integer NOT NULL,
    "Title" text NOT NULL,
    "Description" text,
    "Discount" integer,
    "VoucherCode" text,
    "StartDate" timestamp with time zone NOT NULL,
    "EndDate" timestamp with time zone NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Promotions" PRIMARY KEY ("PromoId"),
    CONSTRAINT "FK_Promotions_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId") ON DELETE CASCADE
);

CREATE TABLE "RefreshTokens" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "Token" text NOT NULL,
    "ExpiresAt" timestamp with time zone NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "IsRevoked" boolean NOT NULL,
    "DeviceInfo" text,
    CONSTRAINT "PK_RefreshTokens" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_RefreshTokens_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("UserId") ON DELETE CASCADE
);

CREATE TABLE "Staff" (
    "StaffId" integer GENERATED BY DEFAULT AS IDENTITY,
    "PlaceId" integer NOT NULL,
    "UserId" integer,
    "FullName" text NOT NULL,
    "Phone" text,
    "Role" text NOT NULL,
    "IsActive" boolean NOT NULL,
    "JoinedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Staff" PRIMARY KEY ("StaffId"),
    CONSTRAINT "FK_Staff_Places_PlaceId" FOREIGN KEY ("PlaceId") REFERENCES "Places" ("PlaceId") ON DELETE CASCADE
);

